import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    Scripts scripts;
    String author;
    Repository repository;
    List<String> files;
    String license;
    Dependencies dependencies;
    DevDependencies devDependencies;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.scripts,
        required this.author,
        required this.repository,
        required this.files,
        required this.license,
        required this.dependencies,
        required this.devDependencies,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        scripts: Scripts.fromJson(json["scripts"]),
        author: json["author"],
        repository: Repository.fromJson(json["repository"]),
        files: List<String>.from(json["files"].map((x) => x)),
        license: json["license"],
        dependencies: Dependencies.fromJson(json["dependencies"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "scripts": scripts.toJson(),
        "author": author,
        "repository": repository.toJson(),
        "files": List<dynamic>.from(files.map((x) => x)),
        "license": license,
        "dependencies": dependencies.toJson(),
        "devDependencies": devDependencies.toJson(),
    };
}

class Dependencies {
    Dependencies();

    factory Dependencies.fromJson(Map<String, dynamic> json) => Dependencies(
    );

    Map<String, dynamic> toJson() => {
    };
}

