        required this.eslint,
        required this.flowParser,
        required this.rimraf,
        required this.rxjs,
        required this.semver,
        required this.tap,
        required this.temp,
        required this.yarn,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        babelCore: json["babel-core"],
        eslint: json["eslint"],
