class Repository {
    String type;
    String url;

    Repository({
        required this.type,
        required this.url,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
    };
}

